**Verilog‑style instruction‑decoder – “no‑latch” combinational case**

Below is a compact, latch‑free template that shows how to pull the opcode out of the 32‑bit instruction, route the correct immediate‑format logic, and sign‑extend the immediate in a single combinational block.  
All outputs are driven in *every* branch of the `case`, so the synthesiser never has to infer a latch.

```verilog
module instr_decoder
  #(parameter XLEN = 32)
  (
    input  wire [31:0]  inst,          // fetched instruction
    output reg  [6:0]   opcode,        // 7‑bit opcode
    output reg  [2:0]   funct3,        // 3‑bit funct3
    output reg  [6:0]   funct7,        // 7‑bit funct7
    output reg  [XLEN-1:0] imm,        // sign‑extended immediate
    output reg  [4:0]   rs1, rs2, rd   // register specifiers
  );

  // ------------------------------------------------------------------
  // 1.  Extract the fixed fields (no combinational hazard)
  // ------------------------------------------------------------------
  always @(*) begin
    opcode = inst[6:0];
    funct3 = inst[14:12];
    funct7 = inst[31:25];
    rs1    = inst[19:15];
    rs2    = inst[24:20];
    rd     = inst[11:7];

    // ----------------------------------------------------------------
    // 2.  Default values – guarantees every output is driven
    // ----------------------------------------------------------------
    imm = {XLEN{1'b0}};

    // ----------------------------------------------------------------
    // 3.  Decode the opcode and build the correct immediate
    // ----------------------------------------------------------------
    case (opcode)
      // R‑type – no immediate
      7'b0110011: imm = {XLEN{1'b0}};

      // I‑type (loads, immediates, jalr)
      7'b0000011, 7'b0010011, 7'b1100111: begin
        // imm[31:20] → imm[XLEN-1:0] with sign‑extension
        imm = {{(XLEN-12){inst[31]}}, inst[31:20]};
      end

      // S‑type (stores)
      7'b0100011: begin
        // imm[11:5] = inst[31:25], imm[4:0] = inst[11:7]
        imm = {{(XLEN-12){inst[31]}},
               inst[31:25],
               inst[11:7]};
      end

      // B‑type (branches)
      7'b1100011: begin
        // imm[12] = inst[31], imm[10:5] = inst[30:25],
        // imm[4:1] = inst[11:8], imm[11] = inst[7]
        imm = {{(XLEN-13){inst[31]}},
               inst[31],          // imm[12]
               inst[7],           // imm[11]
               inst[30:25],       // imm[10:5]
               inst[11:8],        // imm[4:1]
               1'b0};             // imm[0] = 0
      end

      // U‑type (lui, auipc)
      7'b0110111, 7'b0010111: begin
        // imm[31:12] = inst[31:12], lower 12 bits = 0
        imm = {inst[31:12], 12'b0};
      end

      // J‑type (jal)
      7'b1101111: begin
        // imm[20] = inst[31], imm[10:1] = inst[30:21],
        // imm[11] = inst[20], imm[19:12] = inst[19:12]
        imm = {{(XLEN-21){inst[31]}},
               inst[31],          // imm[20]
               inst[19:12],       // imm[19:12]
               inst[20],          // imm[11]
               inst[30:21],       // imm[10:1]
               1'b0};             // imm[0] = 0
      end

      // ----------------------------------------------------------------
      // 4.  Default case – keep imm zero (already set above)
      // ----------------------------------------------------------------
      default: imm = {XLEN{1'b0}};
    endcase
  end

endmodule
```

